const item = $input.first();
const bridge_base_url = (item.json.bridge_base_url || '').trim();
const bridge_api_key = item.json.bridge_api_key || '';
const records = item.json.records || [];

const integration_params = {
  bridge_base_url,
  bridge_api_key,
  tally_port: 9000,
  sync_enabled: true
};

if (records.length === 0) {
  return [{
    json: {
      __empty_batch: true,
      count: 0,
      records: [],
      bridge_base_url,
      bridge_api_key,
      integration_params
    }
  }];
}

return records.map(record => ({
  json: {
    ...record,
    bridge_base_url,
    bridge_api_key,
    integration_params: {
      ...(typeof record.integration_params === 'object' && record.integration_params !== null
        ? record.integration_params : {}),
      bridge_base_url,
      bridge_api_key,
      tally_port: (record.integration_params || {}).tally_port || 9000,
      sync_enabled: true
    }
  }
}));

// DB rows from Lookup Existing Company In DB (direct input wire)
const dbItems = $input.all();
const dbMap = {};
for (const item of dbItems) {
  const r = item.json;
  if (r.erp_sync_id) dbMap[r.erp_sync_id] = r;
  if (r.tally_company_name) dbMap[r.tally_company_name] = r;
  if (r.name) dbMap[r.name] = r;
}

// Tally records from IF Tally Batch Empty? false branch
// Safe to reference — IF node is purely upstream, no downstream chain
const tallyItems = $('IF Tally Batch Empty?').all();

return tallyItems.map(item => {
  const t = item.json;
  const match =
    dbMap[t.erp_sync_id] ||
    dbMap[t.tally_company_name] ||
    dbMap[t.name] ||
    {};
  return {
    json: {
      ...t,
      company_id: match.company_id || null,
      is_active: match.is_active !== undefined ? match.is_active : null,
      tally_auto_sync: match.tally_auto_sync !== undefined ? match.tally_auto_sync : null
    }
  };
});

// Merge tally record data with company_id from either existing lookup or bootstrap insert
const items = $input.all();
const out = [];
for (const item of items) {
  const row = item.json;
  // company_id must be present at this point (either from lookup or from bootstrap insert)
  out.push({ json: { ...row } });
}
return out;

const out = [];

for (const item of $input.all()) {
  const row = item.json;
  const records = row.records || [];
  const syncRunId = row.sync_run_id || null;
  const companyId = row.company_id || null;

  if (records.length === 0 && row.__empty_batch === true) {
    out.push({
      json: {
        __empty_batch: true,
        count: 0,
        records: [],
        sync_run_id: syncRunId,
        company_id: companyId
      }
    });
    continue;
  }

  const toProcess = records.length > 0 ? records : [{
    erp_sync_id: row.erp_sync_id,
    name: row.name,
    trade_name: row.trade_name,
    type: row.type,
    gstin: row.gstin,
    tax_id: row.tax_id,
    pan: row.pan,
    cin: row.cin,
    tan: row.tan,
    address: row.address,
    city: row.city,
    state: row.state,
    pincode: row.pincode,
    phone: row.phone,
    email: row.email,
    website: row.website,
    fy_start: row.fy_start,
    currency: row.currency,
    books_from: row.books_from,
    tally_company_name: row.tally_company_name,
    tally_license_serial: row.tally_license_serial,
    tally_version: row.tally_version,
    integration_params: row.integration_params,
    raw_payload: row.raw_payload
  }];

  for (const record of toProcess) {
    out.push({
      json: {
        ...record,
        sync_run_id: syncRunId,
        company_id: companyId
      }
    });
  }
}

return out;

const syncRunId = $json.sync_run_id || null;
const companyId = $json.company_id || null;

return [{
  json: {
    sync_run_id: syncRunId,
    company_id: companyId,
    run_status: 'success',
    fetched_count: 0,
    staged_count: 0,
    promoted_count: 0,
    skipped_count: 0,
    error_count: 0
  }
}];

const items = $input.all();
if (items.length === 0) {
  return [{ json: { __success_branch: true } }];
}
return items.map(i => ({ json: { ...i.json, __success_branch: true } }));

const allItems = $input.all();

const syncRunItem = allItems.find(i => i.json.sync_run_id !== undefined);
const syncRunId = syncRunItem?.json?.sync_run_id ?? null;
const companyId = syncRunItem?.json?.company_id ?? null;
const fetchedCount = Number(syncRunItem?.json?.fetched_count || 0);

const promoted = allItems.filter(i => {
  const j = i.json || {};
  return !!(j.id && j.erp_sync_id && j.source_hash);
}).length;

const staged = allItems.filter(i => {
  const j = i.json || {};
  return !!(j.erp_sync_id || j.id);
}).length;

const skipped = Math.max(fetchedCount - promoted, 0);

return [{
  json: {
    sync_run_id: syncRunId,
    company_id: companyId,
    run_status: 'success',
    fetched_count: fetchedCount,
    staged_count: staged,
    promoted_count: promoted,
    skipped_count: skipped,
    error_count: 0
  }
}];

// Early empty batch — no company rows needed, just return minimal summary
return [{
  json: {
    __empty_batch: true,
    sync_run_id: null,
    company_id: null,
    run_status: 'success',
    fetched_count: 0,
    staged_count: 0,
    promoted_count: 0,
    skipped_count: 0,
    error_count: 0
  }
}];
